// Initialize query parameters for Sunbiz API
// Query for new subs matching PRIMARY_NAICS formed < 180 days ago
const oneEightyDaysAgo = new Date();
oneEightyDaysAgo.setDate(oneEightyDaysAgo.getDate() - 180);
const formattedDate = oneEightyDaysAgo.toISOString().split('T')[0];
const primaryNaics = $env.PRIMARY_NAICS || '561720';

return [{
  json: {
    query_date: formattedDate,
    state: 'FL',
    naics: primaryNaics,
    query_status: 'active',
    page: 1,
    limit: 100,
    total_found: 0,
    processed_count: 0,
    timestamp: new Date().toISOString()
  }
}];

// Parse Sunbiz response and extract company records
const response = $node['Query Sunbiz API - Primary NAICS'].json || { results: [], total: 0 };

if (!response.results || response.results.length === 0) {
  return [{
    json: {
      records: [],
      total_count: 0,
      message: 'No new janitorial subs found from Sunbiz query'
    }
  }];
}

const records = response.results.map((company, idx) => ({
  json: {
    index: idx + 1,
    legal_name: company.company_name || '',
    dba: company.dba_name || '',
    sunbiz_status: company.status || 'ACTIVE',
    date_formed: company.date_formed || '',
    naics: company.naics || '561720',
    naics_description: company.naics_description || 'Janitorial Services',
    officer_name: company.principal_officer || '',
    contact_name: company.principal_officer || '',
    registered_address: company.registered_address || '',
    physical_address: company.mailing_address || '',
    county: company.county || '',
    zip: company.zip || '',
    sunbiz_record_id: company.record_id || '',
    source: 'Sunbiz',
    created_at: new Date().toISOString()
  }
}));

return records;

// Check if already exists and if opted out
const existing = $node['Dedup Check - Airtable'].json?.records || [];
const alreadyExists = existing.length > 0;
const isOptedOut = alreadyExists && existing[0].fields?.opt_out === true;

return [{
  json: {
    ...($node['Parse Sunbiz Records'].json),
    already_exists: alreadyExists,
    is_opted_out: isOptedOut,
    existing_record_id: alreadyExists ? existing[0].id : null,
    should_skip: isOptedOut
  }
}];

// Classify sub into category based on business signals
// Categories: Commercial, Residential, Specialty, GovCon

const legalName = ($node['Filter - Skip Opted Out Only'].json.legal_name || '').toLowerCase();
const dba = ($node['Filter - Skip Opted Out Only'].json.dba || '').toLowerCase();
const combined = legalName + ' ' + dba;

let sub_category = 'Cleaning';
let classification_reasoning = '';

// GovCon signals
if (combined.includes('federal') || combined.includes('government') || combined.includes('state') || combined.includes('municipal') || combined.includes('contract')) {
  sub_category = 'GovCon';
  classification_reasoning = 'Government-related keywords detected';
} 
// Residential signals (std/deep/STR = short-term rental)
else if (combined.includes('residential') || combined.includes('home') || combined.includes('house') || combined.includes('apartment') || combined.includes('airbnb') || combined.includes('str ') || combined.includes('short-term')) {
  sub_category = 'Residential';
  classification_reasoning = 'Residential service keywords detected';
} 
// Specialty signals (carpet/pressure/junk/specialized)
else if (combined.includes('carpet') || combined.includes('pressure') || combined.includes('wash') || combined.includes('window') || combined.includes('junk') || combined.includes('removal') || combined.includes('carpet') || combined.includes('floor') || combined.includes('specialized')) {
  sub_category = 'Specialty';
  classification_reasoning = 'Specialty service keywords detected';
} 
// Commercial signals (offices/retail/commercial/commercial)
else if (combined.includes('commercial') || combined.includes('office') || combined.includes('retail') || combined.includes('corporate') || combined.includes('business') || combined.includes('medical') || combined.includes('clinic')) {
  sub_category = 'Commercial';
  classification_reasoning = 'Commercial service keywords detected';
}
// Default to Commercial if nothing matched
else {
  sub_category = 'Commercial';
  classification_reasoning = 'Default classification (insufficient signal data)';
}

return [{
  json: {
    ...($node['Filter - Skip Opted Out Only'].json),
    sub_category: sub_category,
    classification_reasoning: classification_reasoning
  }
}];

// Prepare record for SUBS_STAGING table
const enriched = $node['Enrich Sub - Contact Details'].json || {};

return [{
  json: {
    legal_name: $node['Classify Sub Category'].json.legal_name,
    contact_name: enriched.contact_name || $node['Classify Sub Category'].json.contact_name || '',
    business_email: enriched.business_email || enriched.email || '',
    phone: enriched.phone || '',
    website: enriched.website || '',
    date_formed: $node['Classify Sub Category'].json.date_formed,
    county: $node['Classify Sub Category'].json.county,
    sub_category: $node['Classify Sub Category'].json.sub_category,
    status: 'New',
    source: 'Sunbiz',
    notes: `NAICS: 561720 (Janitorial Services). Formed: ${$node['Classify Sub Category'].json.date_formed}. Officer: ${$node['Classify Sub Category'].json.officer_name}. Address: ${$node['Classify Sub Category'].json.physical_address}. Classification: ${$node['Classify Sub Category'].json.classification_reasoning}`,
    sunbiz_status: $node['Classify Sub Category'].json.sunbiz_status,
    sunbiz_record_id: $node['Classify Sub Category'].json.sunbiz_record_id,
    officer_name: $node['Classify Sub Category'].json.officer_name,
    registered_address: $node['Classify Sub Category'].json.registered_address,
    physical_address: $node['Classify Sub Category'].json.physical_address,
    zip: $node['Classify Sub Category'].json.zip
  }
}];

